"""
MKT Matthew chapters 22-28 — three-tier translation written directly to draft JSON files.
Run: python3 scripts/mkt-matthew-22-28.py
"""
import json, pathlib

ROOT  = pathlib.Path(__file__).parent.parent
DRAFT = ROOT / 'data' / 'translation' / 'draft'

def load(tier, book):
    p = DRAFT / tier / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save(tier, book, data):
    p = DRAFT / tier / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

MATTHEW = {
 "22": {
  "1": {"L":"And Jesus answered and spake again in parables unto them, saying:","M":"Jesus spoke to them again in parables, saying:","T":"Jesus continued teaching them in parables."},
  "2": {"L":"The kingdom of heaven is likened unto a certain king, who made a marriage feast for his son,","M":"The kingdom of heaven is like a king who prepared a wedding banquet for his son.","T":"The kingdom of heaven is like a king who threw a wedding banquet for his son."},
  "3": {"L":"and sent forth his servants to call them that were bidden to the marriage feast: and they would not come.","M":"He sent his servants to those who had been invited to the banquet to tell them to come, but they refused to come.","T":"He sent his servants to summon the invited guests—but they refused to come."},
  "4": {"L":"Again he sent forth other servants, saying: Tell them that are bidden, Behold, I have made ready my dinner; my oxen and my fatlings are killed, and all things are ready: come to the marriage feast.","M":"Then he sent some more servants and said: Tell those who have been invited that I have prepared my dinner: My oxen and fattened cattle have been slaughtered, and everything is ready. Come to the wedding banquet.","T":"He sent more servants with this message: Tell the guests everything is ready—the banquet is prepared, come now."},
  "5": {"L":"But they made light of it, and went their ways, one to his own farm, another to his merchandise;","M":"But they paid no attention and went off—one to his field, another to his business.","T":"But they ignored it and went about their business—one to his farm, another to his shop."},
  "6": {"L":"and the rest laid hold on his servants, and treated them shamefully, and killed them.","M":"The rest seized his servants, mistreated them and killed them.","T":"The rest seized his servants, abused them, and killed them."},
  "7": {"L":"But the king was wroth; and he sent his armies, and destroyed those murderers, and burned their city.","M":"The king was enraged. He sent his army and destroyed those murderers and burned their city.","T":"The king was furious. He sent his army, destroyed those murderers, and burned their city."},
  "8": {"L":"Then saith he to his servants: The wedding is ready, but they that were bidden were not worthy.","M":"Then he said to his servants: The wedding banquet is ready, but those I invited did not deserve to come.","T":"Then he said to his servants: The banquet is ready, but the invited guests weren't worthy."},
  "9": {"L":"Go ye therefore unto the partings of the highways, and as many as ye shall find, bid to the marriage feast.","M":"So go to the street corners and invite to the banquet anyone you find.","T":"Go to the street corners and invite anyone you find."},
  "10": {"L":"And those servants went out into the highways, and gathered together all as many as they found, both bad and good: and the wedding was filled with guests.","M":"So the servants went out into the streets and gathered all the people they could find, the bad as well as the good, and the wedding hall was filled with guests.","T":"The servants went out and brought in everyone they could find—good and bad alike—and the banquet hall was packed."},
  "11": {"L":"But when the king came in to behold the guests, he saw there a man who had not on a wedding garment;","M":"But when the king came in to see the guests, he noticed a man there who was not wearing wedding clothes.","T":"When the king came in to greet the guests, he spotted a man not wearing wedding clothes."},
  "12": {"L":"and he saith unto him: Friend, how camest thou in hither not having a wedding garment? And he was speechless.","M":"He asked: How did you get in here without wedding clothes, friend? The man was speechless.","T":"Friend, he said, how did you get in here without proper wedding attire? The man had nothing to say."},
  "13": {"L":"Then the king said to the servants: Bind him hand and foot, and cast him out into the outer darkness; there shall be the weeping and gnashing of teeth.","M":"Then the king told the attendants: Tie him hand and foot, and throw him outside, into the darkness, where there will be weeping and gnashing of teeth.","T":"The king told his attendants: Bind him hand and foot and throw him into the outer darkness—where there is weeping and grinding of teeth."},
  "14": {"L":"For many are called, but few are chosen.","M":"For many are invited, but few are chosen.","T":"Many are invited—but few are chosen."},
  "15": {"L":"Then went the Pharisees, and took counsel how they might ensnare him in his talk.","M":"Then the Pharisees went out and laid plans to trap him in his words.","T":"The Pharisees left and plotted how to trap him with his own words."},
  "16": {"L":"And they send to him their disciples, with the Herodians, saying: Teacher, we know that thou art true, and teachest the way of God in truth, and carest not for any one; for thou regardest not the person of men.","M":"They sent their disciples to him along with the Herodians. Teacher, they said, we know that you are a man of integrity and that you teach the way of God in accordance with the truth. You aren't swayed by others, because you pay no attention to who they are.","T":"They sent their disciples along with some Herodians to say: Teacher, we know you are truthful and teach God's way honestly—you don't play favorites or care what anyone thinks."},
  "17": {"L":"Tell us therefore, What thinkest thou? Is it lawful to give tribute unto Caesar, or not?","M":"Tell us then, what is your opinion? Is it right to pay the imperial tax to Caesar or not?","T":"So tell us—is it right to pay taxes to Caesar or not?"},
  "18": {"L":"But Jesus perceived their wickedness, and said: Why make ye trial of me, ye hypocrites?","M":"But Jesus, knowing their evil intent, said: You hypocrites, why are you trying to trap me?","T":"Jesus saw through their trap: You hypocrites—why are you testing me?"},
  "19": {"L":"Show me the tribute money. And they brought unto him a penny.","M":"Show me the coin used for paying the tax. They brought him a denarius,","T":"Show me the coin used for the tax. They handed him a denarius."},
  "20": {"L":"And he saith unto them: Whose is this image and superscription?","M":"and he asked them: Whose image is this? And whose inscription?","T":"He asked: Whose image and inscription is this?"},
  "21": {"L":"They say unto him: Caesar's. Then saith he unto them: Render therefore unto Caesar the things that are Caesar's; and unto God the things that are God's.","M":"Caesar's, they replied. Then he said to them: So give back to Caesar what is Caesar's, and to God what is God's.","T":"Caesar's, they said. Then he replied: Give to Caesar what belongs to Caesar—and give to God what belongs to God."},
  "22": {"L":"And when they heard it, they marvelled, and left him, and went away.","M":"When they heard this, they were amazed. So they left him and went away.","T":"They were astonished. They left him and went away."},
  "23": {"L":"On that day there came to him Sadducees, they that say there is no resurrection; and they asked him,","M":"That same day the Sadducees, who say there is no resurrection, came to him with a question.","T":"That same day the Sadducees—who deny the resurrection—came to him with a question."},
  "24": {"L":"saying: Teacher, Moses said, If a man die, having no children, his brother shall marry his wife, and raise up seed unto his brother.","M":"Teacher, they said, Moses told us that if a man dies without having children, his brother must marry the widow and raise up offspring for him.","T":"Teacher, Moses said that if a man dies without children, his brother must marry the widow and produce heirs for him."},
  "25": {"L":"Now there were with us seven brethren; and the first married and deceased, and having no seed left his wife unto his brother;","M":"Now there were seven brothers among us. The first one married and died, and since he had no children, he left his wife to his brother.","T":"Among us there were seven brothers. The first married and then died childless, leaving his wife to his brother."},
  "26": {"L":"in like manner the second also, and the third, unto the seventh.","M":"The same thing happened with the second and third brother, right on down to the seventh.","T":"The same happened with the second and third, down to the seventh."},
  "27": {"L":"And after them all, the woman died.","M":"Finally, the woman died.","T":"Finally the woman died too."},
  "28": {"L":"In the resurrection therefore whose wife shall she be of the seven? for they all had her.","M":"Now then, at the resurrection, whose wife will she be of the seven, since all of them were married to her?","T":"So in the resurrection—whose wife will she be? All seven were married to her."},
  "29": {"L":"But Jesus answered and said unto them: Ye do err, not knowing the scriptures, nor the power of God.","M":"Jesus replied: You are in error because you do not know the Scriptures or the power of God.","T":"Jesus replied: You're wrong—because you don't understand Scripture or the power of God."},
  "30": {"L":"For in the resurrection they neither marry, nor are given in marriage, but are as angels in heaven.","M":"At the resurrection people will neither marry nor be given in marriage; they will be like the angels in heaven.","T":"At the resurrection, people don't marry or give in marriage—they're like the angels in heaven."},
  "31": {"L":"But as touching the resurrection of the dead, have ye not read that which was spoken unto you by God, saying,","M":"But about the resurrection of the dead—have you not read what God said to you:","T":"As for the resurrection of the dead—haven't you read what God himself said:"},
  "32": {"L":"I am the God of Abraham, and the God of Isaac, and the God of Jacob? God is not the God of the dead, but of the living.","M":"I am the God of Abraham, the God of Isaac, and the God of Jacob? He is not the God of the dead but of the living.","T":"I am the God of Abraham, the God of Isaac, the God of Jacob. He is not the God of the dead but of the living."},
  "33": {"L":"And when the multitudes heard it, they were astonished at his teaching.","M":"When the crowds heard this, they were astonished at his teaching.","T":"When the crowds heard this, they were astonished at his teaching."},
  "34": {"L":"But the Pharisees, when they heard that he had put the Sadducees to silence, gathered themselves together.","M":"Hearing that Jesus had silenced the Sadducees, the Pharisees got together.","T":"When the Pharisees heard that Jesus had silenced the Sadducees, they regrouped."},
  "35": {"L":"And one of them, a lawyer, asked him a question, trying him:","M":"One of them, an expert in the law, tested him with this question:","T":"One of them, a legal expert, tried to trap him:"},
  "36": {"L":"Teacher, which is the great commandment in the law?","M":"Teacher, which is the greatest commandment in the Law?","T":"Teacher, which commandment in the Law is the greatest?"},
  "37": {"L":"And he said unto him: Thou shalt love the Lord thy God with all thy heart, and with all thy soul, and with all thy mind.","M":"Jesus replied: Love the Lord your God with all your heart and with all your soul and with all your mind.","T":"Jesus replied: Love the Lord your God with your whole heart, your whole soul, and your whole mind."},
  "38": {"L":"This is the great and first commandment.","M":"This is the first and greatest commandment.","T":"This is the first and greatest commandment."},
  "39": {"L":"And a second like unto it is this: Thou shalt love thy neighbour as thyself.","M":"And the second is like it: Love your neighbour as yourself.","T":"And the second is just like it: Love your neighbor as yourself."},
  "40": {"L":"On these two commandments the whole law hangeth, and the prophets.","M":"All the Law and the Prophets hang on these two commandments.","T":"Every law and every prophet hangs on these two commandments."},
  "41": {"L":"Now while the Pharisees were gathered together, Jesus asked them a question,","M":"While the Pharisees were gathered together, Jesus asked them,","T":"While the Pharisees were still gathered, Jesus put a question to them:"},
  "42": {"L":"saying: What think ye of the Christ? whose son is he? They say unto him: The son of David.","M":"What do you think about the Messiah? Whose son is he? The son of David, they replied.","T":"What do you think about the Messiah—whose son is he? The son of David, they replied."},
  "43": {"L":"He saith unto them: How then doth David in the Spirit call him Lord, saying,","M":"He said to them: How is it then that David, speaking by the Spirit, calls him Lord? For he says:","T":"Then how, Jesus asked, does David, speaking by the Spirit, call him Lord? He says:"},
  "44": {"L":"The Lord said unto my Lord, Sit thou on my right hand, till I put thine enemies underneath thy feet?","M":"The Lord said to my Lord: Sit at my right hand until I put your enemies under your feet.","T":"The Lord said to my Lord: Sit at my right hand until I place your enemies as a footstool under your feet."},
  "45": {"L":"If David then calleth him Lord, how is he his son?","M":"If then David calls him Lord, how can he be his son?","T":"If David calls him Lord, how can he be David's son?"},
  "46": {"L":"And no one was able to answer him a word, neither durst any man from that day forth ask him any more questions.","M":"No one could say a word in reply, and from that day on no one dared to ask him any more questions.","T":"No one could answer him a word, and from that day on no one dared question him further."}
 },
 "23": {
  "1": {"L":"Then spake Jesus to the multitudes and to his disciples,","M":"Then Jesus said to the crowds and to his disciples:","T":"Jesus then addressed the crowds and his disciples."},
  "2": {"L":"saying: The scribes and the Pharisees sit on Moses' seat;","M":"The teachers of the law and the Pharisees sit in Moses' seat.","T":"The religious scholars and Pharisees occupy Moses' seat of authority."},
  "3": {"L":"all things therefore whatsoever they bid you, these do and observe; but do not ye after their works; for they say, and do not.","M":"So you must be careful to do everything they tell you. But do not do what they do, for they do not practise what they preach.","T":"So follow what they teach, but don't imitate what they do—because they say one thing and do another."},
  "4": {"L":"Yea, they bind heavy burdens and grievous to be borne, and lay them on men's shoulders; but they themselves will not move them with their finger.","M":"They tie up heavy, cumbersome loads and put them on other people's shoulders, but they themselves are not willing to lift a finger to move them.","T":"They pile heavy burdens on people's shoulders but won't lift a finger to help carry them."},
  "5": {"L":"But all their works they do to be seen of men; for they make broad their phylacteries, and enlarge the borders of their garments,","M":"Everything they do is done for people to see: They make their phylacteries wide and the tassels on their garments long;","T":"Everything they do is a performance for an audience. They make their prayer boxes wide and their tassels long."},
  "6": {"L":"and love the chief place at feasts, and the chief seats in the synagogues,","M":"they love the place of honour at banquets and the most important seats in the synagogues;","T":"They love the best seats at banquets and the front seats in synagogues."},
  "7": {"L":"and the salutations in the marketplaces, and to be called of men, Rabbi.","M":"they love to be greeted with respect in the market-places and to be called Rabbi by others.","T":"They love being greeted with respect in public and being called Rabbi."},
  "8": {"L":"But be not ye called Rabbi; for one is your teacher, and all ye are brethren.","M":"But you are not to be called Rabbi, for you have one Teacher, and you are all brothers.","T":"But you are not to be called Rabbi—you have one Teacher, and you are all on equal footing as brothers and sisters."},
  "9": {"L":"And call no man your father on the earth; for one is your Father, which is in heaven.","M":"And do not call anyone on earth father, for you have one Father, and he is in heaven.","T":"And don't call anyone on earth Father as a title of spiritual authority—you have one Father, and he is in heaven."},
  "10": {"L":"Neither be ye called masters; for one is your master, even the Christ.","M":"Nor are you to be called instructors, for you have one Instructor, the Messiah.","T":"And don't be called Leaders—you have one Leader, the Messiah."},
  "11": {"L":"But he that is greatest among you shall be your servant.","M":"The greatest among you will be your servant.","T":"The greatest among you will be the one who serves."},
  "12": {"L":"And whosoever shall exalt himself shall be humbled; and whosoever shall humble himself shall be exalted.","M":"For those who exalt themselves will be humbled, and those who humble themselves will be exalted.","T":"Those who promote themselves will be brought low; those who make themselves low will be lifted up."},
  "13": {"L":"But woe unto you, scribes and Pharisees, hypocrites! for ye shut the kingdom of heaven against men; for ye enter not in yourselves, neither suffer ye them that are entering in to enter.","M":"Woe to you, teachers of the law and Pharisees, you hypocrites! You shut the door of the kingdom of heaven in people's faces. You yourselves do not enter, nor will you let those enter who are trying to.","T":"How terrible for you, religious scholars and Pharisees—you pretenders! You slam the door of God's kingdom in people's faces. You don't enter yourselves, and you block those who are trying to enter."},
  "14": {"L":"Woe unto you, scribes and Pharisees, hypocrites! for ye devour widows' houses, and for a pretence ye make long prayer; therefore ye shall receive greater condemnation.","M":"Woe to you, teachers of the law and Pharisees, you hypocrites! You devour widows' houses and for a show make lengthy prayers. Therefore you will be punished more severely.","T":"How terrible for you, religious scholars and Pharisees—you pretenders! You exploit widows and offer long prayers as a cover. Your judgment will be all the heavier."},
  "15": {"L":"Woe unto you, scribes and Pharisees, hypocrites! for ye compass sea and land to make one proselyte; and when he is become so, ye make him twofold more a son of hell than yourselves.","M":"Woe to you, teachers of the law and Pharisees, you hypocrites! You travel over land and sea to win a single convert, and when you have succeeded, you make them twice as much a child of hell as you are.","T":"How terrible for you, religious scholars and Pharisees—you pretenders! You travel sea and land to win a single convert, and then make them twice as fit for Gehenna as you are."},
  "16": {"L":"Woe unto you, ye blind guides, that say: Whosoever shall swear by the temple, it is nothing; but whosoever shall swear by the gold of the temple, he is a debtor.","M":"Woe to you, blind guides! You say: If anyone swears by the temple, it means nothing; but anyone who swears by the gold of the temple is bound by that oath.","T":"How terrible for you, blind guides! You say: Swearing by the temple means nothing, but swearing by the temple's gold is binding."},
  "17": {"L":"Ye fools and blind; for which is greater, the gold, or the temple that hath sanctified the gold?","M":"You blind fools! Which is greater: the gold, or the temple that makes the gold sacred?","T":"You blind fools! Which is greater—the gold, or the temple that makes the gold sacred?"},
  "18": {"L":"And: Whosoever shall swear by the altar, it is nothing; but whosoever shall swear by the gift that is upon it, he is a debtor.","M":"You also say: If anyone swears by the altar, it means nothing; but anyone who swears by the gift on the altar is bound by that oath.","T":"You also say: Swearing by the altar means nothing, but swearing by the gift on it is binding."},
  "19": {"L":"Ye blind; for which is greater, the gift, or the altar that sanctifieth the gift?","M":"You blind men! Which is greater: the gift, or the altar that makes the gift sacred?","T":"You blind men! Which is greater—the gift, or the altar that makes the gift sacred?"},
  "20": {"L":"He therefore that sweareth by the altar, sweareth by it, and by all things thereon.","M":"Therefore, anyone who swears by the altar swears by it and by everything on it.","T":"So whoever swears by the altar swears by it and everything on it."},
  "21": {"L":"And he that sweareth by the temple, sweareth by it, and by him that dwelleth therein.","M":"And anyone who swears by the temple swears by it and by the one who dwells in it.","T":"Whoever swears by the temple swears by it and by the One who dwells in it."},
  "22": {"L":"And he that sweareth by the heaven, sweareth by the throne of God, and by him that sitteth thereon.","M":"And anyone who swears by heaven swears by God's throne and by the one who sits on it.","T":"And whoever swears by heaven swears by God's throne and the One who sits on it."},
  "23": {"L":"Woe unto you, scribes and Pharisees, hypocrites! for ye tithe mint and anise and cummin, and have left undone the weightier matters of the law: justice, and mercy, and faith; but these ye ought to have done, and not to have left the other undone.","M":"Woe to you, teachers of the law and Pharisees, you hypocrites! You give a tenth of your spices—mint, dill and cumin. But you have neglected the more important matters of the law—justice, mercy and faithfulness. You should have practised the latter, without neglecting the former.","T":"How terrible for you, religious scholars and Pharisees—you pretenders! You carefully tithe your herbs—mint, dill, and cumin—while neglecting the weightier matters of the Law: justice, compassion, and faithfulness. You should have practiced these without neglecting the others."},
  "24": {"L":"Ye blind guides, that strain out the gnat, and swallow the camel.","M":"You blind guides! You strain out a gnat but swallow a camel.","T":"Blind guides! You strain out a gnat from your cup but swallow a whole camel."},
  "25": {"L":"Woe unto you, scribes and Pharisees, hypocrites! for ye cleanse the outside of the cup and of the platter, but within they are full of extortion and excess.","M":"Woe to you, teachers of the law and Pharisees, you hypocrites! You clean the outside of the cup and dish, but inside they are full of greed and self-indulgence.","T":"How terrible for you, religious scholars and Pharisees—you pretenders! You polish the outside of the cup and plate, while the inside is filled with greed and self-indulgence."},
  "26": {"L":"Thou blind Pharisee, cleanse first the inside of the cup and of the platter, that the outside thereof may become clean also.","M":"Blind Pharisee! First clean the inside of the cup and dish, and then the outside also will be clean.","T":"Blind Pharisee! Clean the inside of the cup first—then the outside will be clean too."},
  "27": {"L":"Woe unto you, scribes and Pharisees, hypocrites! for ye are like unto whited sepulchres, which outwardly appear beautiful, but inwardly are full of dead men's bones, and of all uncleanness.","M":"Woe to you, teachers of the law and Pharisees, you hypocrites! You are like whitewashed tombs, which look beautiful on the outside but on the inside are full of the bones of the dead and everything unclean.","T":"How terrible for you, religious scholars and Pharisees—you pretenders! You're like freshly whitewashed tombs—beautiful on the outside but full of dead bones and rottenness within."},
  "28": {"L":"Even so ye also outwardly appear righteous unto men, but inwardly ye are full of hypocrisy and iniquity.","M":"In the same way, on the outside you appear to people as righteous but on the inside you are full of hypocrisy and wickedness.","T":"In the same way, you appear righteous to everyone—but inside you are full of hypocrisy and lawlessness."},
  "29": {"L":"Woe unto you, scribes and Pharisees, hypocrites! for ye build the sepulchres of the prophets, and garnish the tombs of the righteous,","M":"Woe to you, teachers of the law and Pharisees, you hypocrites! You build tombs for the prophets and decorate the graves of the righteous.","T":"How terrible for you, religious scholars and Pharisees—you pretenders! You build elaborate memorials for the prophets and decorate the tombs of the righteous."},
  "30": {"L":"and say: If we had been in the days of our fathers, we should not have been partakers with them in the blood of the prophets.","M":"And you say: If we had lived in the days of our ancestors, we would not have taken part with them in shedding the blood of the prophets.","T":"And you say: If we had lived in our ancestors' time, we would never have joined in killing the prophets."},
  "31": {"L":"Wherefore ye witness to yourselves, that ye are sons of them that slew the prophets.","M":"So you testify against yourselves that you are the descendants of those who murdered the prophets.","T":"In saying that, you testify against yourselves—you are descendants of those who murdered the prophets."},
  "32": {"L":"Fill ye up then the measure of your fathers.","M":"Go ahead, then, and complete what your ancestors started!","T":"Go ahead—finish what your ancestors started!"},
  "33": {"L":"Ye serpents, ye offspring of vipers, how shall ye escape the judgment of hell?","M":"You snakes! You brood of vipers! How will you escape being condemned to hell?","T":"You snakes—snake-spawn! How will you escape Gehenna's judgment?"},
  "34": {"L":"Therefore, behold, I send unto you prophets, and wise men, and scribes; some of them shall ye kill and crucify; and some of them shall ye scourge in your synagogues, and persecute from city to city;","M":"Therefore I am sending you prophets and sages and teachers. Some of them you will kill and crucify; others you will flog in your synagogues and pursue from town to town.","T":"I am sending you prophets, sages, and scholars. You will kill and crucify some of them; you will flog others in your synagogues and hound them from town to town."},
  "35": {"L":"that upon you may come all the righteous blood shed on the earth, from the blood of Abel the righteous unto the blood of Zachariah son of Barachiah, whom ye slew between the sanctuary and the altar.","M":"And so upon you will come all the righteous blood that has been shed on earth, from the blood of righteous Abel to the blood of Zechariah son of Berekiah, whom you murdered between the temple and the altar.","T":"The result will be that all the righteous blood shed on earth will fall on you—from the blood of Abel down to Zechariah son of Berechiah, whom you murdered between the sanctuary and the altar."},
  "36": {"L":"Verily I say unto you, All these things shall come upon this generation.","M":"Truly I tell you, all this will come on this generation.","T":"I tell you truly—all of this will fall on this generation."},
  "37": {"L":"O Jerusalem, Jerusalem, that killeth the prophets, and stoneth them that are sent unto her! how often would I have gathered thy children together, even as a hen gathereth her chickens under her wings, and ye would not!","M":"Jerusalem, Jerusalem, you who kill the prophets and stone those sent to you, how often I have longed to gather your children together, as a hen gathers her chicks under her wings, and you were not willing.","T":"Jerusalem, Jerusalem—you who kill the prophets and stone those God sends to you! How many times I have wanted to gather your children together the way a hen gathers her chicks under her wings—but you refused."},
  "38": {"L":"Behold, your house is left unto you desolate.","M":"Look, your house is left to you desolate.","T":"Look—your house is being left to you desolate."},
  "39": {"L":"For I say unto you, Ye shall not see me henceforth, till ye shall say, Blessed is he that cometh in the name of the Lord.","M":"For I tell you, you will not see me again until you say: Blessed is he who comes in the name of the Lord.","T":"For I tell you—you won't see me again until you say: Blessed is the one who comes in the name of the Lord."}
 },
 "24": {
  "1": {"L":"And Jesus went out from the temple, and was going on his way; and his disciples came to him to show him the buildings of the temple.","M":"Jesus left the temple and was walking away when his disciples came up to him to call his attention to its buildings.","T":"Jesus left the temple and was walking away when his disciples came to point out the impressive temple buildings."},
  "2": {"L":"But he answered and said unto them: See ye not all these things? verily I say unto you, There shall not be left here one stone upon another, that shall not be thrown down.","M":"Do you see all these things? he asked. Truly I tell you, not one stone here will be left on another; every one will be thrown down.","T":"He replied: Do you see all this? I tell you truly—not one stone here will be left on another; every single one will be thrown down."},
  "3": {"L":"And as he sat on the mount of Olives, the disciples came unto him privately, saying: Tell us, when shall these things be? and what shall be the sign of thy coming, and of the end of the world?","M":"As Jesus was sitting on the Mount of Olives, the disciples came to him privately. Tell us, they said, when will this happen, and what will be the sign of your coming and of the end of the age?","T":"As he sat on the Mount of Olives, the disciples came to him privately: Tell us—when will all this happen? And what will signal your coming and the end of the age?"},
  "4": {"L":"And Jesus answered and said unto them: Take heed that no man lead you astray.","M":"Jesus answered: Watch out that no one deceives you.","T":"Jesus replied: Be on guard—don't let anyone deceive you."},
  "5": {"L":"For many shall come in my name, saying: I am the Christ; and shall lead many astray.","M":"For many will come in my name, claiming: I am the Messiah, and will deceive many.","T":"Many will come in my name claiming to be the Messiah, and they will mislead many people."},
  "6": {"L":"And ye shall hear of wars and rumours of wars; see that ye be not troubled: for these things must needs come to pass; but the end is not yet.","M":"You will hear of wars and rumours of wars, but see to it that you are not alarmed. Such things must happen, but the end is still to come.","T":"You'll hear about wars and rumors of wars—don't be alarmed. These things must happen, but they don't mean the end has arrived."},
  "7": {"L":"For nation shall rise against nation, and kingdom against kingdom; and there shall be famines and earthquakes in divers places.","M":"Nation will rise against nation, and kingdom against kingdom. There will be famines and earthquakes in various places.","T":"Nations and kingdoms will rise against each other. There will be famines and earthquakes in various places."},
  "8": {"L":"But all these things are the beginning of travail.","M":"All these are the beginning of birth pains.","T":"But all of this is just the beginning of the birth pains."},
  "9": {"L":"Then shall they deliver you up unto tribulation, and shall kill you; and ye shall be hated of all the nations for my name's sake.","M":"Then you will be handed over to be persecuted and put to death, and you will be hated by all nations because of me.","T":"Then they will hand you over to be persecuted and killed, and you will be hated by all nations because of me."},
  "10": {"L":"And then shall many stumble, and shall deliver up one another, and shall hate one another.","M":"At that time many will turn away from the faith and will betray and hate each other,","T":"At that time many will fall away from the faith, betraying and hating one another."},
  "11": {"L":"And many false prophets shall arise, and shall lead many astray.","M":"and many false prophets will appear and deceive many people.","T":"Many false prophets will rise up and mislead many."},
  "12": {"L":"And because iniquity shall be multiplied, the love of the many shall wax cold.","M":"Because of the increase of wickedness, the love of most will grow cold,","T":"Because lawlessness will multiply, the love of most people will grow cold."},
  "13": {"L":"But he that endureth to the end, the same shall be saved.","M":"but the one who stands firm to the end will be saved.","T":"But whoever endures to the end will be saved."},
  "14": {"L":"And this gospel of the kingdom shall be preached in the whole world for a testimony unto all the nations; and then shall the end come.","M":"And this gospel of the kingdom will be preached in the whole world as a testimony to all nations, and then the end will come.","T":"And this good news of the kingdom will be proclaimed throughout the entire world as a witness to all nations—and then the end will come."},
  "15": {"L":"When therefore ye see the abomination of desolation, which was spoken of through Daniel the prophet, standing in the holy place (let him that readeth understand),","M":"So when you see standing in the holy place the abomination that causes desolation, spoken of through the prophet Daniel—let the reader understand—","T":"So when you see what Daniel the prophet called the abomination that causes desolation, standing in the holy place—reader, pay careful attention—"},
  "16": {"L":"then let them that are in Judaea flee unto the mountains;","M":"then let those who are in Judea flee to the mountains.","T":"then those in Judea must flee to the mountains."},
  "17": {"L":"let him that is on the housetop not go down to take out the things that are in his house;","M":"Let no one on the housetop go down to take anything out of the house.","T":"Don't stop to take anything from your house."},
  "18": {"L":"and let him that is in the field not return back to take his cloak.","M":"Let no one in the field go back to get their cloak.","T":"If you're in a field, don't go back for your cloak."},
  "19": {"L":"But woe unto them that are with child and to them that give suck in those days!","M":"How dreadful it will be in those days for pregnant women and nursing mothers!","T":"How terrible it will be for pregnant women and nursing mothers in those days!"},
  "20": {"L":"And pray ye that your flight be not in the winter, neither on a sabbath;","M":"Pray that your flight will not take place in winter or on the Sabbath.","T":"Pray that your escape won't happen in winter or on the Sabbath."},
  "21": {"L":"for then shall be great tribulation, such as hath not been from the beginning of the world until now, no, nor ever shall be.","M":"For then there will be great distress, unequalled from the beginning of the world until now—and never to be equalled again.","T":"Because at that time there will be suffering greater than anything that has ever happened since the world began—or ever will happen again."},
  "22": {"L":"And except those days had been shortened, no flesh would have been saved; but for the elect's sake those days shall be shortened.","M":"If those days had not been cut short, no one would survive, but for the sake of the elect those days will be shortened.","T":"If those days hadn't been cut short, no living person would survive. But for the sake of God's chosen people, those days will be shortened."},
  "23": {"L":"Then if any man shall say unto you: Lo, here is the Christ, or: Here; believe it not.","M":"At that time if anyone says to you: Look, here is the Messiah! or, There he is! do not believe it.","T":"At that time, if anyone says to you: Look, the Messiah is here! or There he is!—don't believe it."},
  "24": {"L":"For there shall arise false Christs, and false prophets, and shall show great signs and wonders; so as to lead astray, if possible, even the elect.","M":"For false messiahs and false prophets will appear and perform great signs and wonders to deceive, if possible, even the elect.","T":"False messiahs and false prophets will appear and perform impressive signs and wonders, enough to mislead even God's chosen people if that were possible."},
  "25": {"L":"Behold, I have told you beforehand.","M":"See, I have told you ahead of time.","T":"I've warned you ahead of time."},
  "26": {"L":"If therefore they shall say unto you: Behold, he is in the wilderness; go not forth: Behold, he is in the inner chambers; believe it not.","M":"So if anyone tells you: There he is, out in the wilderness, do not go out; or, Here he is, in the inner rooms, do not believe it.","T":"So if someone says: He's out in the desert!—don't go. Or: He's hiding in a secret room!—don't believe it."},
  "27": {"L":"For as the lightning cometh forth from the east, and is seen even unto the west; so shall be the coming of the Son of man.","M":"For as lightning that comes from the east is visible even in the west, so will be the coming of the Son of Man.","T":"Because the coming of the Son of Man will be like lightning—visible from east to west across the whole sky."},
  "28": {"L":"Wheresoever the carcase is, there will the eagles be gathered together.","M":"Wherever there is a carcass, there the vultures will gather.","T":"Wherever there's a carcass, the vultures will gather."},
  "29": {"L":"But immediately after the tribulation of those days the sun shall be darkened, and the moon shall not give her light, and the stars shall fall from heaven, and the powers of the heavens shall be shaken;","M":"Immediately after the distress of those days the sun will be darkened, and the moon will not give its light; the stars will fall from the sky, and the heavenly bodies will be shaken.","T":"Immediately after the suffering of those days, the sun will go dark, the moon will stop shining, the stars will fall from the sky, and the powers of heaven will be shaken."},
  "30": {"L":"and then shall appear the sign of the Son of man in heaven; and then shall all the tribes of the earth mourn, and they shall see the Son of man coming on the clouds of heaven with power and great glory.","M":"Then will appear the sign of the Son of Man in heaven. And then all the peoples of the earth will mourn when they see the Son of Man coming on the clouds of heaven, with power and great glory.","T":"Then the sign of the Son of Man will appear in the sky, and all the nations of the earth will mourn as they see the Son of Man coming on the clouds of heaven with power and immense glory."},
  "31": {"L":"And he shall send forth his angels with a great sound of a trumpet, and they shall gather together his elect from the four winds, from one end of heaven to the other.","M":"And he will send his angels with a loud trumpet call, and they will gather his elect from the four winds, from one end of the heavens to the other.","T":"He will send out his angels with the great blast of a trumpet, and they will gather his chosen people from the four winds—from one end of heaven to the other."},
  "32": {"L":"Now from the fig tree learn her parable: when her branch is now become tender, and putteth forth its leaves, ye know that the summer is nigh;","M":"Now learn this lesson from the fig tree: As soon as its twigs get tender and its leaves come out, you know that summer is near.","T":"Learn from the fig tree: when its branches become tender and its leaves come out, you know summer is close."},
  "33": {"L":"even so ye also, when ye see all these things, know ye that he is nigh, even at the doors.","M":"Even so, when you see all these things, you know that it is near, right at the door.","T":"In the same way, when you see all these things happening, know that it is near—right at the door."},
  "34": {"L":"Verily I say unto you, This generation shall not pass away, till all these things be accomplished.","M":"Truly I tell you, this generation will certainly not pass away until all these things have happened.","T":"I tell you truly—this generation will certainly not pass away before all these things happen."},
  "35": {"L":"Heaven and earth shall pass away, but my words shall not pass away.","M":"Heaven and earth will pass away, but my words will never pass away.","T":"Heaven and earth will pass away—but my words will never pass away."},
  "36": {"L":"But of that day and hour knoweth no one, not even the angels of heaven, neither the Son, but the Father only.","M":"But about that day or hour no one knows, not even the angels in heaven, nor the Son, but only the Father.","T":"But no one knows the day or hour—not the angels in heaven, not even the Son—only the Father."},
  "37": {"L":"And as were the days of Noah, so shall be the coming of the Son of man.","M":"As it was in the days of Noah, so it will be at the coming of the Son of Man.","T":"The coming of the Son of Man will be just like the days of Noah."},
  "38": {"L":"For as in those days which were before the flood they were eating and drinking, marrying and giving in marriage, until the day that Noah entered into the ark,","M":"For in the days before the flood, people were eating and drinking, marrying and giving in marriage, up to the day Noah entered the ark;","T":"Before the flood, people were eating and drinking, marrying and being married, right up until the day Noah entered the ark."},
  "39": {"L":"and they knew not until the flood came, and took them all away; so shall be the coming of the Son of man.","M":"and they knew nothing about what would happen until the flood came and took them all away. That is how it will be at the coming of the Son of Man.","T":"They had no idea what was coming until the flood swept them all away. That's exactly how the coming of the Son of Man will be."},
  "40": {"L":"Then shall two men be in the field; one is taken, and one is left.","M":"Two men will be in the field; one will be taken and the other left.","T":"Two men will be in a field—one taken, the other left."},
  "41": {"L":"Two women shall be grinding at the mill; one is taken, and one is left.","M":"Two women will be grinding with a hand mill; one will be taken and the other left.","T":"Two women grinding grain—one taken, the other left."},
  "42": {"L":"Watch therefore: for ye know not on what day your Lord cometh.","M":"Therefore keep watch, because you do not know on what day your Lord will come.","T":"So stay awake—because you don't know what day your Lord is coming."},
  "43": {"L":"But know this, that if the master of the house had known in what watch the thief was coming, he would have watched, and would not have suffered his house to be broken through.","M":"But understand this: If the owner of the house had known at what time of night the thief was coming, he would have kept watch and would not have let his house be broken into.","T":"Understand this: if a homeowner had known when a thief was coming, he would have stayed awake and not let his house be broken into."},
  "44": {"L":"Therefore be ye also ready; for in an hour that ye think not the Son of man cometh.","M":"So you also must be ready, because the Son of Man will come at an hour when you do not expect him.","T":"So you must also be ready—the Son of Man will come at a moment when you least expect it."},
  "45": {"L":"Who then is the faithful and wise servant, whom his lord hath set over his household, to give them their food in due season?","M":"Who then is the faithful and wise servant, whom the master has put in charge of the servants in his household to give them their food at the proper time?","T":"Who is the faithful and wise servant that the master has put in charge of his household staff to give them their food at the right time?"},
  "46": {"L":"Blessed is that servant, whom his lord when he cometh shall find so doing.","M":"It will be good for that servant whose master finds him doing so when he returns.","T":"How favored that servant will be when the master comes and finds him doing his job."},
  "47": {"L":"Verily I say unto you, that he will set him over all that he hath.","M":"Truly I tell you, he will put him in charge of all his possessions.","T":"I tell you, the master will put him in charge of everything he owns."},
  "48": {"L":"But if that evil servant shall say in his heart: My lord tarrieth;","M":"But suppose that servant is wicked and says to himself: My master is staying away a long time,","T":"But if that servant turns wicked and thinks: My master is taking his time—"},
  "49": {"L":"and shall begin to beat his fellow-servants, and shall eat and drink with the drunken;","M":"and he then begins to beat his fellow servants and to eat and drink with drunkards.","T":"and starts beating his fellow servants and carousing with drunkards—"},
  "50": {"L":"the lord of that servant shall come in a day when he expecteth not, and in an hour when he knoweth not,","M":"The master of that servant will come on a day when he does not expect him and at an hour he is not aware of.","T":"that servant's master will come on a day he doesn't expect and at an hour he doesn't know."},
  "51": {"L":"and shall cut him asunder, and appoint his portion with the hypocrites; there shall be the weeping and the gnashing of teeth.","M":"He will cut him to pieces and assign him a place with the hypocrites, where there will be weeping and gnashing of teeth.","T":"He will cut him to pieces and assign him a place with the pretenders—where there is weeping and grinding of teeth."}
 },
 "25": {
  "1": {"L":"Then shall the kingdom of heaven be likened unto ten virgins, who took their lamps, and went forth to meet the bridegroom.","M":"At that time the kingdom of heaven will be like ten virgins who took their lamps and went out to meet the bridegroom.","T":"The kingdom of heaven will be like ten young women who took their lamps and went to wait for the groom."},
  "2": {"L":"And five of them were foolish, and five were wise.","M":"Five of them were foolish and five were wise.","T":"Five were foolish and five were wise."},
  "3": {"L":"For the foolish, when they took their lamps, took no oil with them;","M":"The foolish ones took their lamps but did not take any oil with them.","T":"The foolish ones took their lamps but brought no extra oil."},
  "4": {"L":"but the wise took oil in their vessels with their lamps.","M":"The wise ones, however, took oil in jars along with their lamps.","T":"The wise ones brought extra oil in jars along with their lamps."},
  "5": {"L":"Now while the bridegroom tarried, they all slumbered and slept.","M":"The bridegroom was a long time in coming, and they all became drowsy and fell asleep.","T":"The bridegroom was delayed, and they all dozed off and fell asleep."},
  "6": {"L":"But at midnight there is a cry: Behold, the bridegroom! Come ye forth to meet him.","M":"At midnight the cry rang out: Here's the bridegroom! Come out to meet him!","T":"At midnight a shout rang out: The groom is here! Come out to meet him!"},
  "7": {"L":"Then all those virgins arose, and trimmed their lamps.","M":"Then all the virgins woke up and trimmed their lamps.","T":"All ten woke up and trimmed their lamps."},
  "8": {"L":"And the foolish said unto the wise: Give us of your oil; for our lamps are going out.","M":"The foolish ones said to the wise: Give us some of your oil; our lamps are going out.","T":"The foolish ones said to the wise: Give us some of your oil—our lamps are dying out."},
  "9": {"L":"But the wise answered, saying: Peradventure there will not be enough for us and you; go ye rather to them that sell, and buy for yourselves.","M":"No, they replied, there may not be enough for both us and you. Instead, go to those who sell oil and buy some for yourselves.","T":"No, the wise ones said—there won't be enough for all of us. Go buy your own."},
  "10": {"L":"And while they went away to buy, the bridegroom came; and they that were ready went in with him to the marriage feast; and the door was shut.","M":"But while they were on their way to buy the oil, the bridegroom arrived. The virgins who were ready went in with him to the wedding banquet. And the door was shut.","T":"While they were gone to buy oil, the groom arrived. The ones who were ready went in with him to the banquet—and the door was shut."},
  "11": {"L":"Afterward came also the other virgins, saying: Lord, Lord, open to us.","M":"Later the others also came. Lord, Lord, they said, open the door for us!","T":"Later the others arrived: Lord, Lord, let us in!"},
  "12": {"L":"But he answered and said: Verily I say unto you, I know you not.","M":"But he replied: Truly I tell you, I don't know you.","T":"But he replied: I tell you truthfully—I don't know you."},
  "13": {"L":"Watch therefore, for ye know not the day nor the hour.","M":"Therefore keep watch, because you do not know the day or the hour.","T":"So stay awake—you don't know the day or the hour."},
  "14": {"L":"For it is as when a man, going into another country, called his own servants, and delivered unto them his goods.","M":"Again, it will be like a man going on a journey, who called his servants and entrusted his wealth to them.","T":"It's also like a man who was going on a long journey and called his servants together to entrust his assets to them."},
  "15": {"L":"And unto one he gave five talents, to another two, to another one; to each according to his several ability; and he went on his journey.","M":"To one he gave five bags of gold, to another two bags, and to another one bag, each according to his ability. Then he went on his journey.","T":"To one he gave five talents, to another two, to another one—each according to their ability. Then he left."},
  "16": {"L":"Straightway he that received the five talents went and traded with them, and made other five talents.","M":"The man who had received five bags of gold went at once and put his money to work and gained five bags more.","T":"The one who received five talents went right to work and earned five more."},
  "17": {"L":"In like manner he also that received the two gained other two.","M":"So also, the one with two bags of gold gained two more.","T":"The one with two did the same and gained two more."},
  "18": {"L":"But he that received the one went away and digged in the earth, and hid his lord's money.","M":"But the man who had received one bag went off, dug a hole in the ground and hid his master's money.","T":"But the one who received one talent dug a hole and buried his master's money."},
  "19": {"L":"Now after a long time the lord of those servants cometh, and maketh a reckoning with them.","M":"After a long time the master of those servants returned and settled accounts with them.","T":"After a long time the master returned and settled accounts with them."},
  "20": {"L":"And he that received the five talents came and brought other five talents, saying: Lord, thou deliveredst unto me five talents; lo, I have gained other five talents.","M":"The man who had received five bags of gold brought the other five. Master, he said, you entrusted me with five bags of gold. See, I have gained five more.","T":"The one with five talents came: Master, you entrusted five talents to me—look, I've gained five more."},
  "21": {"L":"His lord said unto him: Well done, good and faithful servant; thou hast been faithful over a few things, I will set thee over many things; enter thou into the joy of thy lord.","M":"His master replied: Well done, good and faithful servant! You have been faithful with a few things; I will put you in charge of many things. Come and share your master's happiness!","T":"His master said: Well done, good and faithful servant! You were trustworthy with a small amount—I'll put you in charge of much more. Come and share in your master's joy!"},
  "22": {"L":"And he also that received the two talents came and said: Lord, thou deliveredst unto me two talents; lo, I have gained other two talents.","M":"The man with two bags of gold also came. Master, he said, you entrusted me with two bags of gold; see, I have gained two more.","T":"The one with two talents came: Master, you gave me two—I've earned two more."},
  "23": {"L":"His lord said unto him: Well done, good and faithful servant; thou hast been faithful over a few things, I will set thee over many things; enter thou into the joy of thy lord.","M":"His master replied: Well done, good and faithful servant! You have been faithful with a few things; I will put you in charge of many things. Come and share your master's happiness!","T":"Well done, good and faithful servant! You were trustworthy with a little—I'll put you in charge of much more. Come and share your master's joy!"},
  "24": {"L":"And he also that had received the one talent came and said: Lord, I knew thee that thou art a hard man, reaping where thou didst not sow, and gathering where thou didst not scatter;","M":"Then the man who had received one bag of gold came. Master, he said, I knew that you are a hard man, harvesting where you have not sown and gathering where you have not scattered seed.","T":"Then the one with one talent came: Master, I knew you were a hard man—reaping where you didn't sow, gathering where you didn't scatter."},
  "25": {"L":"and I was afraid, and went away and hid thy talent in the earth; lo, thou hast thine own.","M":"So I was afraid and went out and hid your gold in the ground. See, here is what belongs to you.","T":"I was afraid, so I buried it. Here—it's yours back."},
  "26": {"L":"But his lord answered and said unto him: Thou wicked and slothful servant, thou knewest that I reap where I sowed not, and gather where I did not scatter;","M":"His master replied: You wicked, lazy servant! So you knew that I harvest where I have not sown and gather where I have not scattered seed?","T":"His master replied: You wicked, lazy servant! You knew I reap where I haven't sown?"},
  "27": {"L":"thou oughtest therefore to have put my money to the bankers, and at my coming I should have received back mine own with interest.","M":"Well then, you should have put my money on deposit with the bankers, so that when I returned I would have received it back with interest.","T":"Then you should have at least deposited it with a bank so I'd get it back with interest."},
  "28": {"L":"Take ye away therefore the talent from him, and give it unto him that hath the ten talents.","M":"So take the bag of gold from him and give it to the one who has ten bags.","T":"Take the talent from him and give it to the one who has ten."},
  "29": {"L":"For unto every one that hath shall be given, and he shall have abundance; but from him that hath not, even that which he hath shall be taken away.","M":"For whoever has will be given more, and they will have an abundance. Whoever does not have, even what they have will be taken from them.","T":"Those who produce will be given more and have plenty. From those who produce nothing, even what little they have will be taken."},
  "30": {"L":"And cast ye out the unprofitable servant into the outer darkness; there shall be the weeping and gnashing of teeth.","M":"And throw that worthless servant outside, into the darkness, where there will be weeping and gnashing of teeth.","T":"Throw the useless servant into the outer darkness—where there is weeping and grinding of teeth."},
  "31": {"L":"But when the Son of man shall come in his glory, and all the angels with him, then shall he sit on the throne of his glory;","M":"When the Son of Man comes in his glory, and all the angels with him, he will sit on his glorious throne.","T":"When the Son of Man comes in his glory with all the angels, he will sit on his glorious throne."},
  "32": {"L":"and before him shall be gathered all the nations; and he shall separate them one from another, as the shepherd separateth the sheep from the goats;","M":"All the nations will be gathered before him, and he will separate the people one from another as a shepherd separates the sheep from the goats.","T":"All the nations will be gathered before him and he will separate people from one another as a shepherd separates sheep from goats."},
  "33": {"L":"and he shall set the sheep on his right hand, but the goats on the left.","M":"He will put the sheep on his right and the goats on his left.","T":"The sheep he'll place on his right, the goats on his left."},
  "34": {"L":"Then shall the King say unto them on his right hand: Come, ye blessed of my Father, inherit the kingdom prepared for you from the foundation of the world:","M":"Then the King will say to those on his right: Come, you who are blessed by my Father; take your inheritance, the kingdom prepared for you since the creation of the world.","T":"Then the King will say to those on his right: Come, you who are blessed by my Father—receive the kingdom prepared for you since the foundation of the world."},
  "35": {"L":"for I was hungry, and ye gave me to eat; I was thirsty, and ye gave me drink; I was a stranger, and ye took me in;","M":"For I was hungry and you gave me something to eat, I was thirsty and you gave me something to drink, I was a stranger and you invited me in,","T":"Because I was hungry and you fed me; I was thirsty and you gave me something to drink; I was a stranger and you welcomed me;"},
  "36": {"L":"naked, and ye clothed me; I was sick, and ye visited me; I was in prison, and ye came unto me.","M":"I needed clothes and you clothed me, I was ill and you looked after me, I was in prison and you came to visit me.","T":"I had no clothing and you clothed me; I was sick and you cared for me; I was in prison and you visited me."},
  "37": {"L":"Then shall the righteous answer him, saying: Lord, when saw we thee hungry, and fed thee? or athirst, and gave thee drink?","M":"Then the righteous will answer him: Lord, when did we see you hungry and feed you, or thirsty and give you something to drink?","T":"Then the righteous will ask: Lord, when did we see you hungry and feed you, or thirsty and give you a drink?"},
  "38": {"L":"And when saw we thee a stranger, and took thee in? or naked, and clothed thee?","M":"When did we see you a stranger and invite you in, or needing clothes and clothe you?","T":"When did we see you as a stranger and welcome you, or needing clothes and dress you?"},
  "39": {"L":"And when saw we thee sick, or in prison, and came unto thee?","M":"When did we see you ill or in prison and go to visit you?","T":"When did we see you sick or in prison and visit you?"},
  "40": {"L":"And the King shall answer and say unto them: Verily I say unto you, Inasmuch as ye did it unto one of these my brethren, even these least, ye did it unto me.","M":"The King will reply: Truly I tell you, whatever you did for one of the least of these brothers and sisters of mine, you did for me.","T":"The King will reply: I tell you truly—whatever you did for even the least of my brothers and sisters, you did for me."},
  "41": {"L":"Then shall he say also unto them on the left hand: Depart from me, ye cursed, into the eternal fire which is prepared for the devil and his angels:","M":"Then he will say to those on his left: Depart from me, you who are cursed, into the eternal fire prepared for the devil and his angels.","T":"Then he will say to those on his left: Get away from me, you who are cursed—into the eternal fire prepared for the devil and his angels."},
  "42": {"L":"for I was hungry, and ye did not give me to eat; I was thirsty, and ye gave me no drink;","M":"For I was hungry and you gave me nothing to eat, I was thirsty and you gave me nothing to drink,","T":"Because I was hungry and you gave me nothing to eat; I was thirsty and you gave me nothing to drink;"},
  "43": {"L":"I was a stranger, and ye took me not in; naked, and ye clothed me not; sick, and in prison, and ye visited me not.","M":"I was a stranger and you did not invite me in, I needed clothes and you did not clothe me, I was ill and in prison and you did not look after me.","T":"I was a stranger and you didn't welcome me; I had no clothes and you didn't clothe me; I was sick and in prison and you didn't visit me."},
  "44": {"L":"Then shall they also answer, saying: Lord, when saw we thee hungry, or athirst, or a stranger, or naked, or sick, or in prison, and did not minister unto thee?","M":"They also will answer: Lord, when did we see you hungry or thirsty or a stranger or needing clothes or ill or in prison, and did not help you?","T":"Then they will say: Lord, when did we see you hungry or thirsty or a stranger or needing clothes or sick or in prison—and fail to help you?"},
  "45": {"L":"Then shall he answer them, saying: Verily I say unto you, Inasmuch as ye did it not unto one of these least, ye did it not unto me.","M":"He will reply: Truly I tell you, whatever you did not do for one of the least of these, you did not do for me.","T":"He will reply: I tell you truly—whatever you failed to do for even the least of my brothers and sisters, you failed to do for me."},
  "46": {"L":"And these shall go away into eternal punishment; but the righteous into eternal life.","M":"Then they will go away to eternal punishment, but the righteous to eternal life.","T":"Then these will go away into eternal punishment, and the righteous into the life of the age to come."}
 },
 "26": {
  "1": {"L":"And it came to pass, when Jesus had finished all these words, he said unto his disciples,","M":"When Jesus had finished saying all these things, he said to his disciples,","T":"When Jesus had finished all these teachings, he said to his disciples:"},
  "2": {"L":"Ye know that after two days the passover cometh, and the Son of man is delivered up to be crucified.","M":"As you know, the Passover is two days away—and the Son of Man will be handed over to be crucified.","T":"You know that the Passover is two days away—and the Son of Man will be handed over to be crucified."},
  "3": {"L":"Then were gathered together the chief priests, and the elders of the people, unto the court of the high priest, who was called Caiaphas;","M":"Then the chief priests and the elders of the people assembled in the palace of the high priest, whose name was Caiaphas,","T":"At that same time the chief priests and elders gathered at the palace of Caiaphas the high priest."},
  "4": {"L":"and they took counsel together that they might take Jesus by subtlety, and kill him.","M":"and they schemed to arrest Jesus secretly and kill him.","T":"They conspired to arrest Jesus secretly and have him killed."},
  "5": {"L":"But they said: Not during the feast, lest a tumult arise among the people.","M":"But not during the festival, they said, or there may be a riot among the people.","T":"But not during the festival, they said—we don't want a riot among the people."},
  "6": {"L":"Now when Jesus was in Bethany, in the house of Simon the leper,","M":"While Jesus was in Bethany in the home of Simon the Leper,","T":"While Jesus was in Bethany at the home of Simon the Leper,"},
  "7": {"L":"there came unto him a woman having an alabaster cruse of exceeding precious ointment, and she poured it upon his head, as he sat at meat.","M":"a woman came to him with an alabaster jar of very expensive perfume, which she poured on his head as he was reclining at the table.","T":"a woman came to him with an alabaster jar of very expensive perfume and poured it over his head while he was at the table."},
  "8": {"L":"But when the disciples saw it, they were moved with indignation, and said: To what purpose is this waste?","M":"When the disciples saw this, they were indignant. Why this waste? they asked.","T":"The disciples were angry: What a waste!"},
  "9": {"L":"For this ointment might have been sold for much, and given to the poor.","M":"This perfume could have been sold at a high price and the money given to the poor.","T":"This could have been sold for a large sum and given to the poor."},
  "10": {"L":"But Jesus, perceiving it, said unto them: Why trouble ye the woman? for she hath wrought a good work upon me.","M":"Aware of this, Jesus said to them: Why are you bothering this woman? She has done a beautiful thing to me.","T":"Jesus overheard them: Why are you troubling this woman? She has done something beautiful for me."},
  "11": {"L":"For ye have the poor always with you; but me ye have not always.","M":"The poor you will always have with you, but you will not always have me.","T":"The poor will always be with you—but I won't always be here."},
  "12": {"L":"For in that she poured this ointment upon my body, she did it to prepare me for burial.","M":"When she poured this perfume on my body, she did it to prepare me for burial.","T":"By pouring this perfume on me, she prepared my body for burial."},
  "13": {"L":"Verily I say unto you, Wheresoever this gospel shall be preached in the whole world, that also which this woman hath done shall be spoken of for a memorial of her.","M":"Truly I tell you, wherever this gospel is preached throughout the world, what she has done will also be told, in memory of her.","T":"I tell you truly—wherever this good news is proclaimed in all the world, what she has done will be told as well, in her memory."},
  "14": {"L":"Then one of the twelve, who was called Judas Iscariot, went unto the chief priests,","M":"Then one of the Twelve—the one called Judas Iscariot—went to the chief priests","T":"Then Judas Iscariot, one of the twelve, went to the chief priests"},
  "15": {"L":"and said: What are ye willing to give me, and I will deliver him unto you? And they weighed unto him thirty pieces of silver.","M":"and asked: What are you willing to give me if I deliver him over to you? So they counted out for him thirty pieces of silver.","T":"and asked: What will you pay me if I hand him over to you? They counted out thirty pieces of silver."},
  "16": {"L":"And from that time he sought opportunity to deliver him up.","M":"From that time on Judas watched for an opportunity to hand him over.","T":"From that moment Judas was looking for the right opportunity to betray him."},
  "17": {"L":"Now on the first day of unleavened bread the disciples came to Jesus, saying: Where wilt thou that we make ready for thee to eat the passover?","M":"On the first day of the Festival of Unleavened Bread, the disciples came to Jesus and asked: Where do you want us to make preparations for you to eat the Passover?","T":"On the first day of the Festival of Unleavened Bread, the disciples came to Jesus: Where do you want us to prepare the Passover meal?"},
  "18": {"L":"And he said: Go into the city to such a man, and say unto him: The Teacher saith, My time is at hand; I keep the passover at thy house with my disciples.","M":"He replied: Go into the city to a certain man and tell him, The Teacher says: My appointed time is near. I am going to celebrate the Passover with my disciples at your house.","T":"He replied: Go into the city to a certain person and say: The Teacher says his appointed time is near—he will observe the Passover at your house with his disciples."},
  "19": {"L":"And the disciples did as Jesus appointed them; and they made ready the passover.","M":"So the disciples did as Jesus had directed them and prepared the Passover.","T":"The disciples did as Jesus had directed and prepared the Passover meal."},
  "20": {"L":"Now when even was come, he was sitting at meat with the twelve disciples;","M":"When evening came, Jesus was reclining at the table with the Twelve.","T":"When evening came, Jesus was reclining at the table with the twelve."},
  "21": {"L":"and as they were eating, he said: Verily I say unto you, that one of you shall betray me.","M":"And while they were eating, he said: Truly I tell you, one of you will betray me.","T":"During the meal he said: I tell you truly—one of you will betray me."},
  "22": {"L":"And they were exceeding sorrowful, and began to say unto him every one: Is it I, Lord?","M":"They were very sad and began to say to him one after the other: Surely you don't mean me, Lord?","T":"They were deeply grieved and began asking one by one: Surely not I, Lord?"},
  "23": {"L":"And he answered and said: He that dipped his hand with me in the dish, the same shall betray me.","M":"Jesus replied: The one who has dipped his hand into the bowl with me will betray me.","T":"He replied: The one who dipped his hand in the bowl with me—he is the one."},
  "24": {"L":"The Son of man goeth, even as it is written of him; but woe unto that man through whom the Son of man is betrayed! good were it for that man if he had not been born.","M":"The Son of Man will go just as it is written about him. But woe to that man who betrays the Son of Man! It would be better for him if he had not been born.","T":"The Son of Man goes just as Scripture has written of him. But how terrible for the man who betrays him—it would have been better for that man if he had never been born."},
  "25": {"L":"And Judas, who betrayed him, answered and said: Is it I, Rabbi? He saith unto him: Thou hast said.","M":"Then Judas, the one who would betray him, said: Surely you don't mean me, Rabbi? Jesus answered: You have said so.","T":"Then Judas, who was about to betray him, said: Surely not I, Rabbi? Jesus replied: You said it."},
  "26": {"L":"And as they were eating, Jesus took bread, and blessed, and brake it; and he gave to the disciples, and said: Take, eat; this is my body.","M":"While they were eating, Jesus took bread, and when he had given thanks, he broke it and gave it to his disciples, saying: Take and eat; this is my body.","T":"While they were eating, Jesus took bread, gave thanks, broke it and gave it to his disciples: Take and eat—this is my body."},
  "27": {"L":"And he took a cup, and gave thanks, and gave to them, saying: Drink ye all of it;","M":"Then he took a cup, and when he had given thanks, he gave it to them, saying: Drink from it, all of you.","T":"Then he took a cup, gave thanks, and gave it to them: All of you drink from it."},
  "28": {"L":"for this is my blood of the covenant, which is poured out for many unto remission of sins.","M":"This is my blood of the covenant, which is poured out for many for the forgiveness of sins.","T":"This is my blood of the covenant—poured out for many for the forgiveness of sins."},
  "29": {"L":"But I say unto you, I will not drink henceforth of this fruit of the vine, until that day when I drink it new with you in my Father's kingdom.","M":"I tell you, I will not drink from this fruit of the vine from now on until that day when I drink it new with you in my Father's kingdom.","T":"I tell you—I will not drink this fruit of the vine again until that day when I drink it new with you in my Father's kingdom."},
  "30": {"L":"And when they had sung a hymn, they went out unto the mount of Olives.","M":"When they had sung a hymn, they went out to the Mount of Olives.","T":"After singing a hymn, they went out to the Mount of Olives."},
  "31": {"L":"Then saith Jesus unto them: All ye shall be offended in me this night; for it is written: I will smite the shepherd, and the sheep of the flock shall be scattered abroad.","M":"Then Jesus told them: This very night you will all fall away on account of me, for it is written: I will strike the shepherd, and the sheep of the flock will be scattered.","T":"Then Jesus said: This very night every one of you will stumble because of me—for Scripture says: I will strike the shepherd and the sheep of the flock will be scattered."},
  "32": {"L":"But after I am raised up, I will go before you into Galilee.","M":"But after I have risen, I will go ahead of you into Galilee.","T":"But after I am raised, I will go ahead of you to Galilee."},
  "33": {"L":"But Peter answered and said unto him: If all shall be offended in thee, I will never be offended.","M":"Peter replied: Even if all fall away on account of you, I never will.","T":"Peter said: Even if everyone else stumbles because of you, I never will."},
  "34": {"L":"Jesus said unto him: Verily I say unto thee, that this night, before the cock crow, thou shalt deny me thrice.","M":"Truly I tell you, Jesus answered, this very night, before the cock crows, you will disown me three times.","T":"I tell you truly, Jesus replied—this very night, before the rooster crows, you will deny me three times."},
  "35": {"L":"Peter saith unto him: Even if I must die with thee, yet will I not deny thee. Likewise also said all the disciples.","M":"But Peter declared: Even if I have to die with you, I will never disown you. And all the other disciples said the same.","T":"Peter insisted: Even if I have to die with you, I will never deny you. All the other disciples said the same."},
  "36": {"L":"Then cometh Jesus with them unto a place called Gethsemane, and saith unto his disciples: Sit ye here, while I go yonder and pray.","M":"Then Jesus went with his disciples to a place called Gethsemane, and he said to them: Sit here while I go over there and pray.","T":"Then Jesus went with them to a place called Gethsemane and said: Sit here while I go over there to pray."},
  "37": {"L":"And he took with him Peter and the two sons of Zebedee, and began to be sorrowful and sore troubled.","M":"He took Peter and the two sons of Zebedee along with him, and he began to be sorrowful and troubled.","T":"He took Peter and the two sons of Zebedee with him and began to be overwhelmed with sorrow and anguish."},
  "38": {"L":"Then saith he unto them: My soul is exceeding sorrowful, even unto death; abide ye here, and watch with me.","M":"Then he said to them: My soul is overwhelmed with sorrow to the point of death. Stay here and keep watch with me.","T":"He said: My soul is crushed with grief to the point of death. Stay here and keep watch with me."},
  "39": {"L":"And he went forward a little, and fell on his face, and prayed, saying: My Father, if it be possible, let this cup pass away from me; nevertheless, not as I will, but as thou wilt.","M":"Going a little farther, he fell with his face to the ground and prayed: My Father, if it is possible, may this cup be taken from me. Yet not as I will, but as you will.","T":"He went a little further, fell face-down, and prayed: My Father, if it is possible, let this cup pass from me. Yet not as I will—only as you will."},
  "40": {"L":"And he cometh unto the disciples, and findeth them sleeping, and saith unto Peter: What, could ye not watch with me one hour?","M":"Then he returned to his disciples and found them sleeping. Couldn't you men keep watch with me for one hour? he asked Peter.","T":"He returned to the disciples and found them asleep. He said to Peter: So you couldn't stay awake with me for even one hour?"},
  "41": {"L":"Watch and pray, that ye enter not into temptation; the spirit indeed is willing, but the flesh is weak.","M":"Watch and pray so that you will not fall into temptation. The spirit is willing, but the flesh is weak.","T":"Stay awake and pray so you don't fall into temptation. The spirit is eager but the body is weak."},
  "42": {"L":"Again a second time he went away, and prayed, saying: My Father, if this cannot pass away, except I drink it, thy will be done.","M":"He went away a second time and prayed: My Father, if it is not possible for this cup to be taken away unless I drink it, may your will be done.","T":"He went away a second time and prayed: My Father, if this cup cannot pass unless I drink it, then your will be done."},
  "43": {"L":"And he came again and found them sleeping, for their eyes were heavy.","M":"When he came back, he again found them sleeping, because their eyes were heavy.","T":"He came back again and found them asleep—their eyes were heavy with exhaustion."},
  "44": {"L":"And he left them again, and went away, and prayed a third time, saying again the same words.","M":"So he left them and went away once more and prayed the third time, saying the same thing.","T":"He left them again and prayed a third time, saying the same words."},
  "45": {"L":"Then cometh he to the disciples, and saith unto them: Sleep on now, and take your rest; behold, the hour is at hand, and the Son of man is betrayed into the hands of sinners.","M":"Then he returned to the disciples and said to them: Are you still sleeping and resting? Look, the hour has come, and the Son of Man is delivered into the hands of sinners.","T":"Then he came back to the disciples: Still sleeping? Still resting? Look—the hour has arrived. The Son of Man is being handed over to sinners."},
  "46": {"L":"Arise, let us be going; behold, he is at hand that betrayeth me.","M":"Rise! Let us go! Here comes my betrayer!","T":"Get up—let's go. My betrayer is here."},
  "47": {"L":"And while he yet spake, lo, Judas, one of the twelve, came, and with him a great multitude with swords and staves, from the chief priests and elders of the people.","M":"While he was still speaking, Judas, one of the Twelve, arrived. With him was a large crowd armed with swords and clubs, sent from the chief priests and the elders of the people.","T":"While he was still speaking, Judas—one of the twelve—arrived with a large armed crowd sent by the chief priests and elders."},
  "48": {"L":"Now he that betrayed him gave them a sign, saying: Whomsoever I shall kiss, that is he; take him.","M":"Now the betrayer had arranged a signal with them: The one I kiss is the man; arrest him.","T":"The betrayer had arranged a signal: The man I kiss is the one—arrest him."},
  "49": {"L":"And straightway he came to Jesus, and said: Hail, Rabbi; and kissed him.","M":"Going at once to Jesus, Judas said: Greetings, Rabbi! and kissed him.","T":"He went straight to Jesus: Greetings, Rabbi! And he kissed him."},
  "50": {"L":"And Jesus said unto him: Friend, do that for which thou art come. Then they came and laid hands on Jesus, and took him.","M":"Jesus replied: Do what you came for, friend. Then the men stepped forward, seized Jesus and arrested him.","T":"Jesus said: Friend—do what you came to do. Then they stepped forward, grabbed Jesus, and arrested him."},
  "51": {"L":"And behold, one of them that were with Jesus stretched out his hand, and drew his sword, and smote the servant of the high priest, and struck off his ear.","M":"With that, one of Jesus' companions reached for his sword, drew it out and struck the servant of the high priest, cutting off his ear.","T":"Suddenly one of those with Jesus drew his sword and struck the high priest's servant, cutting off his ear."},
  "52": {"L":"Then saith Jesus unto him: Put up again thy sword into its place; for all they that take the sword shall perish with the sword.","M":"Put your sword back in its place, Jesus said to him, for all who draw the sword will die by the sword.","T":"Jesus said: Put your sword away. Everyone who takes up the sword will die by the sword."},
  "53": {"L":"Or thinkest thou that I cannot beseech my Father, and he shall even now send me more than twelve legions of angels?","M":"Do you think I cannot call on my Father, and he will at once put at my disposal more than twelve legions of angels?","T":"Do you think I couldn't call on my Father right now and he would immediately send more than twelve legions of angels?"},
  "54": {"L":"How then should the scriptures be fulfilled, that thus it must be?","M":"But how then would the Scriptures be fulfilled that say it must happen in this way?","T":"But then how would the Scriptures be fulfilled that say this must happen?"},
  "55": {"L":"In that hour said Jesus to the multitudes: Are ye come out as against a robber with swords and staves to seize me? I sat daily in the temple teaching, and ye took me not.","M":"In that hour Jesus said to the crowd: Am I leading a rebellion, that you have come out with swords and clubs to capture me? Every day I sat in the temple courts teaching, and you did not arrest me.","T":"At that moment Jesus said to the crowd: Am I some kind of armed rebel, that you've come out with swords and clubs to take me? Every day I sat teaching in the temple and you didn't arrest me."},
  "56": {"L":"But all this is come to pass, that the scriptures of the prophets might be fulfilled. Then all the disciples left him, and fled.","M":"But this has all taken place that the writings of the prophets might be fulfilled. Then all the disciples deserted him and fled.","T":"But all this has happened to fulfil what the prophets wrote. Then all the disciples deserted him and ran."},
  "57": {"L":"And they that had taken Jesus led him away to Caiaphas the high priest, where the scribes and the elders were gathered together.","M":"Those who had arrested Jesus took him to Caiaphas the high priest, where the teachers of the law and the elders had assembled.","T":"Those who had arrested Jesus took him to Caiaphas the high priest, where the religious scholars and elders had gathered."},
  "58": {"L":"But Peter followed him afar off, unto the court of the high priest, and entered in, and sat with the officers, to see the end.","M":"But Peter followed him at a distance, right up to the courtyard of the high priest. He entered and sat down with the guards to see the outcome.","T":"Peter followed at a distance as far as the high priest's courtyard. He went inside and sat with the guards to see how it would end."},
  "59": {"L":"Now the chief priests and the whole council sought false witness against Jesus, that they might put him to death;","M":"The chief priests and the whole Sanhedrin were looking for false evidence against Jesus so that they could put him to death.","T":"The chief priests and the entire council were looking for false testimony against Jesus to have him executed."},
  "60": {"L":"and they found it not, though many false witnesses came. But afterward came two,","M":"But they did not find any, though many false witnesses came forward. Finally two came forward","T":"But they couldn't find anything, though many false witnesses came forward. Finally two came forward"},
  "61": {"L":"and said: This man said: I am able to destroy the temple of God, and to build it in three days.","M":"and declared: This fellow said, I am able to destroy the temple of God and rebuild it in three days.","T":"and said: This man claimed, I can destroy God's temple and rebuild it in three days."},
  "62": {"L":"And the high priest stood up, and said unto him: Answerest thou nothing? what is it which these witness against thee?","M":"Then the high priest stood up and said to Jesus: Are you not going to answer? What is this testimony that these men are bringing against you?","T":"The high priest stood up: Don't you have an answer? What about this testimony against you?"},
  "63": {"L":"But Jesus held his peace. And the high priest said unto him: I adjure thee by the living God, that thou tell us whether thou art the Christ, the Son of God.","M":"But Jesus remained silent. The high priest said to him: I charge you under oath by the living God: Tell us if you are the Messiah, the Son of God.","T":"Jesus remained silent. The high priest said: I put you under oath by the living God—tell us whether you are the Messiah, the Son of God."},
  "64": {"L":"Jesus saith unto him: Thou hast said; nevertheless I say unto you, Henceforth ye shall see the Son of man sitting at the right hand of Power, and coming on the clouds of heaven.","M":"You have said so, Jesus replied. But I say to all of you: From now on you will see the Son of Man sitting at the right hand of the Mighty One and coming on the clouds of heaven.","T":"Jesus replied: You said it. But I tell you all—from now on you will see the Son of Man seated at the right hand of the Almighty, coming on the clouds of heaven."},
  "65": {"L":"Then the high priest rent his garments, saying: He hath spoken blasphemy; what further need have we of witnesses? behold, now ye have heard the blasphemy;","M":"Then the high priest tore his clothes and said: He has spoken blasphemy! Why do we need any more witnesses? Look, now you have heard the blasphemy.","T":"The high priest tore his robes: He has blasphemed! Why do we need more witnesses? You've heard the blasphemy yourselves!"},
  "66": {"L":"what think ye? They answered and said: He is worthy of death.","M":"What do you think? He is worthy of death, they answered.","T":"What is your verdict? He deserves death, they answered."},
  "67": {"L":"Then did they spit in his face and buffet him; and some smote him with the palms of their hands,","M":"Then they spit in his face and struck him with their fists. Others slapped him","T":"Then they spit in his face and beat him with their fists. Others slapped him,"},
  "68": {"L":"saying: Prophesy unto us, thou Christ; who is he that struck thee?","M":"and said: Prophesy to us, Messiah. Who hit you?","T":"saying: Prophesy to us, Messiah—who hit you?"},
  "69": {"L":"Now Peter was sitting without in the court; and a maid came unto him, saying: Thou also wast with Jesus the Galilean.","M":"Now Peter was sitting out in the courtyard, and a servant girl came to him. You also were with Jesus of Galilee, she said.","T":"Meanwhile Peter was sitting in the courtyard. A servant girl came to him: You were with Jesus of Galilee too."},
  "70": {"L":"But he denied before them all, saying: I know not what thou sayest.","M":"But he denied it before them all. I don't know what you're talking about, he said.","T":"He denied it in front of everyone: I don't know what you're talking about."},
  "71": {"L":"And when he was gone out into the porch, another maid saw him, and saith unto them that were there: This man also was with Jesus the Nazarene.","M":"Then he went out to the gateway, where another servant girl saw him and said to the people there: This fellow was with Jesus of Nazareth.","T":"He went out to the gateway, where another servant girl spotted him and said to the people: This man was with Jesus of Nazareth."},
  "72": {"L":"And again he denied with an oath: I know not the man.","M":"He denied it again, with an oath: I don't know the man!","T":"He denied it again—this time with an oath: I don't know the man!"},
  "73": {"L":"And after a little while they that stood by came and said to Peter: Of a truth thou also art one of them; for thy speech maketh thee known.","M":"After a little while, those standing there went up to Peter and said: Surely you are one of them; your accent gives you away.","T":"A little while later, those standing nearby said: You really are one of them—your accent gives you away."},
  "74": {"L":"Then began he to curse and to swear: I know not the man. And straightway the cock crew.","M":"Then he began to call down curses, and he swore to them: I don't know the man! Immediately a rooster crowed.","T":"Then he began to curse and swear: I don't know the man! And at that moment the rooster crowed."},
  "75": {"L":"And Peter remembered the word which Jesus had said, Before the cock crow, thou shalt deny me thrice; and he went out and wept bitterly.","M":"Then Peter remembered the word Jesus had spoken: Before the rooster crows, you will disown me three times. And he went outside and wept bitterly.","T":"Then Peter remembered what Jesus had said: Before the rooster crows, you will deny me three times. He went outside and wept with bitter grief."}
 },
 "27": {
  "1": {"L":"Now when morning was come, all the chief priests and the elders of the people took counsel against Jesus to put him to death;","M":"Early in the morning, all the chief priests and the elders of the people made their plans to have Jesus executed.","T":"At dawn all the chief priests and elders of the people made their final plan to execute Jesus."},
  "2": {"L":"and they bound him, and led him away, and delivered him up to Pilate the governor.","M":"So they bound him, led him away and handed him over to Pilate the governor.","T":"They bound him, led him away, and handed him over to Pilate the governor."},
  "3": {"L":"Then Judas, who betrayed him, when he saw that he was condemned, repented himself, and brought back the thirty pieces of silver to the chief priests and elders,","M":"When Judas, who had betrayed him, saw that Jesus was condemned, he was seized with remorse and returned the thirty pieces of silver to the chief priests and the elders.","T":"When Judas, who had betrayed him, saw that Jesus had been condemned, he was seized with remorse. He brought back the thirty pieces of silver to the chief priests and elders."},
  "4": {"L":"saying: I have sinned in that I betrayed innocent blood. But they said: What is that to us? see thou to it.","M":"I have sinned, he said, for I have betrayed innocent blood. What is that to us? they replied. That's your responsibility.","T":"I have sinned, he said. I betrayed innocent blood. What's that to us? they replied. That's your problem."},
  "5": {"L":"And he cast down the pieces of silver into the sanctuary, and departed; and he went away and hanged himself.","M":"So Judas threw the money into the temple and left. Then he went away and hanged himself.","T":"Judas threw the money into the temple and left. Then he went out and hanged himself."},
  "6": {"L":"And the chief priests took the pieces of silver, and said: It is not lawful to put them into the treasury, since it is the price of blood.","M":"The chief priests picked up the coins and said: It is against the law to put this into the treasury, since it is blood money.","T":"The chief priests picked up the coins: It's not legal to put this in the temple treasury—it's blood money."},
  "7": {"L":"And they took counsel, and bought with them the potter's field, to bury strangers in.","M":"So they decided to use the money to buy the potter's field as a burial place for foreigners.","T":"After deliberating, they used the money to buy a potter's field as a burial place for foreigners."},
  "8": {"L":"Wherefore that field was called, The field of blood, unto this day.","M":"That is why it has been called the Field of Blood to this day.","T":"That's why that field has been called the Field of Blood to this day."},
  "9": {"L":"Then was fulfilled that which was spoken through Jeremiah the prophet, saying: And they took the thirty pieces of silver, the price of him that was priced, whom certain of the children of Israel did price;","M":"Then what was spoken by Jeremiah the prophet was fulfilled: They took the thirty pieces of silver, the price set on him by the people of Israel,","T":"This fulfilled what Jeremiah the prophet had written: They took the thirty pieces of silver—the price the people of Israel had set on him—"},
  "10": {"L":"and they gave them for the potter's field, as the Lord appointed me.","M":"and they used them to buy the potter's field, as the Lord commanded me.","T":"and bought the potter's field with them, as the Lord directed me."},
  "11": {"L":"Now Jesus stood before the governor; and the governor asked him, saying: Art thou the King of the Jews? And Jesus said unto him: Thou sayest.","M":"Meanwhile Jesus stood before the governor, and the governor asked him: Are you the king of the Jews? You have said so, Jesus replied.","T":"Jesus stood before the governor. The governor asked: Are you the King of the Jews? You say so, Jesus replied."},
  "12": {"L":"And when he was accused by the chief priests and elders, he answered nothing.","M":"When he was accused by the chief priests and the elders, he gave no answer.","T":"When the chief priests and elders accused him, he said nothing."},
  "13": {"L":"Then saith Pilate unto him: Hearest thou not how many things they witness against thee?","M":"Then Pilate asked him: Don't you hear the testimony they are bringing against you?","T":"Pilate asked: Don't you hear the charges they're making against you?"},
  "14": {"L":"And he gave him no answer, not even to one word; insomuch that the governor marvelled greatly.","M":"But Jesus made no reply, not even to a single charge—to the great amazement of the governor.","T":"Jesus gave no reply—not a single word. The governor was astonished."},
  "15": {"L":"Now at the feast the governor was wont to release unto the multitude one prisoner, whom they would.","M":"Now it was the governor's custom at the festival to release a prisoner chosen by the crowd.","T":"At festival time, the governor had a custom of releasing a prisoner chosen by the crowd."},
  "16": {"L":"And they had then a notable prisoner, called Barabbas.","M":"At that time they had a well-known prisoner whose name was Jesus Barabbas.","T":"At that time a notorious prisoner named Barabbas was being held."},
  "17": {"L":"When therefore they were gathered together, Pilate said unto them: Whom will ye that I release unto you? Barabbas, or Jesus who is called Christ?","M":"So when the crowd had gathered, Pilate asked them: Which one do you want me to release to you: Jesus Barabbas, or Jesus who is called the Messiah?","T":"So when the crowd had gathered, Pilate asked: Which one do you want me to release—Barabbas or Jesus who is called the Messiah?"},
  "18": {"L":"For he knew that for envy they had delivered him up.","M":"For he knew it was out of self-interest that they had handed Jesus over to him.","T":"He knew they had handed Jesus over out of jealousy."},
  "19": {"L":"And while he was sitting on the judgment-seat, his wife sent unto him, saying: Have thou nothing to do with that righteous man; for I have suffered many things this day in a dream because of him.","M":"While Pilate was sitting on the judge's seat, his wife sent him this message: Don't have anything to do with that innocent man, for I have suffered a great deal today in a dream because of him.","T":"While Pilate was seated at the judgment seat, his wife sent him a message: Have nothing to do with that innocent man—I suffered greatly in a dream about him today."},
  "20": {"L":"Now the chief priests and the elders persuaded the multitudes that they should ask for Barabbas, and destroy Jesus.","M":"But the chief priests and the elders persuaded the crowd to ask for Barabbas and to have Jesus executed.","T":"But the chief priests and elders had already worked the crowd—persuading them to demand Barabbas and have Jesus executed."},
  "21": {"L":"But the governor answered and said unto them: Which of the two will ye that I release unto you? And they said: Barabbas.","M":"Which of the two do you want me to release to you? asked the governor. Barabbas, they answered.","T":"The governor asked: Which of the two do you want released? Barabbas! they shouted."},
  "22": {"L":"Pilate saith unto them: What then shall I do unto Jesus who is called Christ? They all say: Let him be crucified.","M":"What shall I do, then, with Jesus who is called the Messiah? Pilate asked. They all answered: Crucify him!","T":"Pilate asked: Then what should I do with Jesus who is called the Messiah? Crucify him! they all cried."},
  "23": {"L":"And he said: Why, what evil hath he done? But they cried out exceedingly, saying: Let him be crucified.","M":"Why? What crime has he committed? asked Pilate. But they shouted all the louder: Crucify him!","T":"What crime has he committed? Pilate asked. But they only screamed louder: Crucify him!"},
  "24": {"L":"So when Pilate saw that he prevailed nothing, but rather that a tumult was arising, he took water, and washed his hands before the multitude, saying: I am innocent of the blood of this righteous man; see ye to it.","M":"When Pilate saw that he was getting nowhere, but that instead an uproar was starting, he took water and washed his hands in front of the crowd. I am innocent of this man's blood, he said. It is your responsibility!","T":"When Pilate saw he was getting nowhere—only stirring up more uproar—he took water and washed his hands in front of the crowd: I am innocent of this man's blood. That's your responsibility."},
  "25": {"L":"And all the people answered and said: His blood be on us, and on our children.","M":"All the people answered: His blood is on us and on our children!","T":"All the people answered: His blood be on us and on our children."},
  "26": {"L":"Then released he unto them Barabbas; but Jesus he scourged, and delivered to be crucified.","M":"Then he released Barabbas to them. But he had Jesus flogged, and handed him over to be crucified.","T":"Then he released Barabbas. But he had Jesus flogged and handed him over to be crucified."},
  "27": {"L":"Then the soldiers of the governor took Jesus into the palace, and gathered unto him the whole band.","M":"Then the governor's soldiers took Jesus into the Praetorium and gathered the whole company of soldiers around him.","T":"The governor's soldiers took Jesus into the Praetorium and assembled the entire cohort around him."},
  "28": {"L":"And they stripped him, and put on him a scarlet robe.","M":"They stripped him and put a scarlet robe on him,","T":"They stripped off his clothes and put a scarlet robe on him."},
  "29": {"L":"And they platted a crown of thorns and put it upon his head, and a reed in his right hand; and they kneeled down before him, and mocked him, saying: Hail, King of the Jews!","M":"and then twisted together a crown of thorns and set it on his head. They put a staff in his right hand. Then they knelt in front of him and mocked him. Hail, king of the Jews! they said.","T":"They wove a crown of thorns and jammed it on his head, put a reed in his right hand, and knelt mockingly before him: Hail, King of the Jews!"},
  "30": {"L":"And they spat upon him, and took the reed and smote him on the head.","M":"They spat on him, and took the staff and struck him on the head again and again.","T":"They spat on him and beat him on the head with the reed."},
  "31": {"L":"And when they had mocked him, they took off from him the robe, and put on him his garments, and led him away to crucify him.","M":"After they had mocked him, they took off the robe and put his own clothes on him. Then they led him away to crucify him.","T":"After mocking him, they took off the robe, dressed him in his own clothes, and led him away to be crucified."},
  "32": {"L":"And as they came out, they found a man of Cyrene, Simon by name; him they compelled to go with them, that he might bear his cross.","M":"As they were going out, they met a man from Cyrene, named Simon, and they forced him to carry the cross.","T":"On the way out they came across a man named Simon from Cyrene and forced him to carry the cross."},
  "33": {"L":"And they were come unto a place called Golgotha, that is to say, The place of a skull,","M":"They came to a place called Golgotha (which means the Place of the Skull).","T":"They came to a place called Golgotha—the Place of the Skull."},
  "34": {"L":"they gave him wine to drink mingled with gall; and when he had tasted it, he would not drink.","M":"There they offered Jesus wine to drink, mixed with gall; but after tasting it, he refused to drink it.","T":"They offered him wine mixed with gall. He tasted it but refused to drink."},
  "35": {"L":"And when they had crucified him, they parted his garments among them, casting lots;","M":"When they had crucified him, they divided up his clothes by casting lots.","T":"After crucifying him, they divided his clothing among themselves by casting lots."},
  "36": {"L":"and they sat and watched him there.","M":"And sitting down, they kept watch over him there.","T":"Then they sat down and kept watch over him."},
  "37": {"L":"And they set up over his head his accusation written: This is Jesus the King of the Jews.","M":"Above his head they placed the written charge against him: this is jesus, the king of the jews.","T":"Above his head they posted the written charge against him: THIS IS JESUS, THE KING OF THE JEWS."},
  "38": {"L":"Then are there crucified with him two robbers, one on the right hand and one on the left.","M":"Two rebels were crucified with him, one on his right and one on his left.","T":"Two criminals were crucified alongside him—one on his right, one on his left."},
  "39": {"L":"And they that passed by railed on him, wagging their heads,","M":"Those who passed by hurled insults at him, shaking their heads","T":"People passing by were hurling abuse at him, shaking their heads:"},
  "40": {"L":"and saying: Thou that destroyest the temple, and buildest it in three days, save thyself; if thou art the Son of God, come down from the cross.","M":"and saying: You who are going to destroy the temple and build it in three days, save yourself! Come down from the cross, if you are the Son of God!","T":"You claimed you could destroy the temple and rebuild it in three days—save yourself! Come down from the cross if you're the Son of God!"},
  "41": {"L":"In like manner also the chief priests mocking him, with the scribes and elders, said,","M":"In the same way the chief priests, the teachers of the law and the elders mocked him.","T":"In the same way the chief priests, religious scholars, and elders mocked him:"},
  "42": {"L":"He saved others; himself he cannot save. He is the King of Israel; let him now come down from the cross, and we will believe on him.","M":"He saved others, they said, but he can't save himself! He's the king of Israel! Let him come down now from the cross, and we will believe in him.","T":"He saved others—can't he save himself? He's the King of Israel! Let him come down from the cross right now, and we'll believe in him."},
  "43": {"L":"He trusteth on God; let him deliver him now, if he desireth him; for he said, I am the Son of God.","M":"He trusts in God. Let God rescue him now if he wants him, for he said: I am the Son of God.","T":"He trusted in God—let God rescue him now, if he wants him. He said he was the Son of God."},
  "44": {"L":"And the robbers also that were crucified with him cast upon him the same reproach.","M":"In the same way the rebels who were crucified with him also heaped insults on him.","T":"The criminals crucified alongside him were heaping the same abuse on him."},
  "45": {"L":"Now from the sixth hour there was darkness over all the land until the ninth hour.","M":"From noon until three in the afternoon darkness came over all the land.","T":"From noon until three in the afternoon, darkness covered the whole land."},
  "46": {"L":"And about the ninth hour Jesus cried with a loud voice, saying: Eli, Eli, lama sabachthani? that is, My God, my God, why hast thou forsaken me?","M":"About three in the afternoon Jesus cried out in a loud voice: Eli, Eli, lema sabachthani? (which means My God, my God, why have you forsaken me?).","T":"Around three o'clock Jesus cried out with a loud voice: Eli, Eli, lema sabachthani?—which means: My God, my God, why have you abandoned me?"},
  "47": {"L":"And some of them that stood there, when they heard it, said: This man calleth Elijah.","M":"When some of those standing there heard this, they said: He's calling Elijah.","T":"Some of those standing there heard and said: He's calling for Elijah."},
  "48": {"L":"And straightway one of them ran, and took a sponge, and filled it with vinegar, and put it on a reed, and gave him to drink.","M":"Immediately one of them ran and got a sponge. He filled it with wine vinegar, put it on a staff, and offered it to Jesus to drink.","T":"One of them ran immediately, soaked a sponge in wine vinegar, put it on a reed, and offered it to him to drink."},
  "49": {"L":"And the rest said: Let be; let us see whether Elijah cometh to save him.","M":"The rest said: Now leave him alone. Let's see if Elijah comes to save him.","T":"The others said: Leave him alone—let's see if Elijah comes to save him."},
  "50": {"L":"And Jesus cried again with a loud voice, and yielded up his spirit.","M":"And when Jesus had cried out again in a loud voice, he gave up his spirit.","T":"Jesus cried out again with a loud voice—and released his spirit."},
  "51": {"L":"And behold, the veil of the temple was rent in two from the top to the bottom; and the earth did quake; and the rocks were rent;","M":"At that moment the curtain of the temple was torn in two from top to bottom. The earth shook, the rocks split","T":"At that moment the temple curtain was torn in two from top to bottom. The earth shook and rocks split."},
  "52": {"L":"and the tombs were opened; and many bodies of the saints that had fallen asleep were raised;","M":"and the tombs broke open. The bodies of many holy people who had died were raised to life.","T":"Tombs split open and many holy people who had died were raised to life."},
  "53": {"L":"and coming forth out of the tombs after his resurrection they entered into the holy city and appeared unto many.","M":"They came out of the tombs after Jesus' resurrection and went into the holy city and appeared to many people.","T":"They came out of the tombs after Jesus' resurrection and appeared to many people in the holy city."},
  "54": {"L":"Now the centurion, and they that were with him watching Jesus, when they saw the earthquake, and the things that were done, feared exceedingly, saying: Truly this was the Son of God.","M":"When the centurion and those with him who were guarding Jesus saw the earthquake and all that had happened, they were terrified, and exclaimed: Surely he was the Son of God!","T":"When the centurion and those guarding Jesus saw the earthquake and everything that happened, they were terrified: This man really was the Son of God!"},
  "55": {"L":"And many women were there beholding from afar, who had followed Jesus from Galilee, ministering unto him;","M":"Many women were there, watching from a distance. They had followed Jesus from Galilee to care for his needs.","T":"Many women were watching from a distance—women who had followed Jesus from Galilee and served him."},
  "56": {"L":"among whom was Mary Magdalene, and Mary the mother of James and Joses, and the mother of the sons of Zebedee.","M":"Among them were Mary Magdalene, Mary the mother of James and Joseph, and the mother of Zebedee's sons.","T":"Among them were Mary Magdalene, Mary the mother of James and Joseph, and the mother of Zebedee's sons."},
  "57": {"L":"And when even was come, there came a rich man from Arimathaea, named Joseph, who also himself was Jesus' disciple;","M":"As evening approached, there came a rich man from Arimathea, named Joseph, who had himself become a disciple of Jesus.","T":"As evening came, a wealthy man from Arimathea named Joseph arrived—he had also become a disciple of Jesus."},
  "58": {"L":"this man went to Pilate, and asked for the body of Jesus. Then Pilate commanded it to be given up.","M":"Going to Pilate, he asked for Jesus' body, and Pilate ordered that it be given to him.","T":"He went to Pilate and requested the body of Jesus. Pilate ordered that it be released to him."},
  "59": {"L":"And Joseph took the body, and wrapped it in a clean linen cloth,","M":"Joseph took the body, wrapped it in a clean linen cloth,","T":"Joseph took the body, wrapped it in clean linen cloth,"},
  "60": {"L":"and laid it in his own new tomb, which he had hewn out in the rock; and he rolled a great stone to the door of the tomb, and departed.","M":"and placed it in his own new tomb that he had cut out of the rock. He rolled a big stone in front of the entrance to the tomb and went away.","T":"and placed it in his own new tomb carved out of rock. He rolled a large stone in front of the entrance and went away."},
  "61": {"L":"And Mary Magdalene was there, and the other Mary, sitting over against the sepulchre.","M":"Mary Magdalene and the other Mary were sitting there opposite the tomb.","T":"Mary Magdalene and the other Mary were sitting opposite the tomb, watching."},
  "62": {"L":"Now on the morrow, which is the day after the Preparation, the chief priests and the Pharisees were gathered together unto Pilate,","M":"The next day, the one after Preparation Day, the chief priests and the Pharisees went to Pilate.","T":"The next day—the day after Preparation Day—the chief priests and Pharisees went to Pilate."},
  "63": {"L":"saying: Sir, we remember that that deceiver said while he was yet alive, After three days I rise again.","M":"Sir, they said, we remember that while he was still alive that deceiver said: After three days I will rise again.","T":"Sir, we remember that deceiver claimed while he was still alive: After three days I will rise."},
  "64": {"L":"Command therefore that the sepulchre be made sure until the third day, lest haply his disciples come and steal him away, and say unto the people, He is risen from the dead; and the last error will be worse than the first.","M":"So give the order for the tomb to be made secure until the third day. Otherwise, his disciples may come and steal the body and tell the people that he has been raised from the dead. This last deception will be worse than the first.","T":"So order the tomb secured until the third day. Otherwise his disciples might steal the body and tell the people he rose from the dead. That deception would be worse than the first."},
  "65": {"L":"Pilate said unto them: Ye have a guard; go, make it as sure as ye can.","M":"Take a guard, Pilate answered. Go, make the tomb as secure as you know how.","T":"Pilate said: Take a guard detachment. Go make it as secure as you can."},
  "66": {"L":"So they went, and made the sepulchre sure, sealing the stone, the guard being with them.","M":"So they went and made the tomb secure by putting a seal on the stone and posting the guard.","T":"They went and sealed the stone and posted guards at the tomb."}
 },
 "28": {
  "1": {"L":"Now late on the sabbath day, as it began to dawn toward the first day of the week, came Mary Magdalene and the other Mary to see the sepulchre.","M":"After the Sabbath, at dawn on the first day of the week, Mary Magdalene and the other Mary went to look at the tomb.","T":"After the Sabbath, as the first day of the week was dawning, Mary Magdalene and the other Mary went to see the tomb."},
  "2": {"L":"And behold, there was a great earthquake; for an angel of the Lord descended from heaven, and came and rolled away the stone, and sat upon it.","M":"There was a violent earthquake, for an angel of the Lord came down from heaven and, going to the tomb, rolled back the stone and sat on it.","T":"Suddenly there was a great earthquake—an angel of the Lord descended from heaven, rolled back the stone, and sat on it."},
  "3": {"L":"His appearance was as lightning, and his raiment white as snow;","M":"His appearance was like lightning, and his clothes were white as snow.","T":"His appearance blazed like lightning, and his clothing was white as snow."},
  "4": {"L":"and for fear of him the watchers did quake, and became as dead men.","M":"The guards were so afraid of him that they shook and became like dead men.","T":"The guards were so terrified that they shook and became like corpses."},
  "5": {"L":"And the angel answered and said unto the women: Fear not ye; for I know that ye seek Jesus, who hath been crucified.","M":"The angel said to the women: Do not be afraid, for I know that you are looking for Jesus, who was crucified.","T":"The angel said to the women: Don't be afraid. I know you're looking for Jesus who was crucified."},
  "6": {"L":"He is not here; for he is risen, even as he said. Come, see the place where the Lord lay.","M":"He is not here; he has risen, just as he said. Come and see the place where he lay.","T":"He is not here—he has risen, exactly as he said he would. Come and see where he was lying."},
  "7": {"L":"And go quickly, and tell his disciples, He is risen from the dead; and lo, he goeth before you into Galilee; there shall ye see him; lo, I have told you.","M":"Then go quickly and tell his disciples: He has risen from the dead and is going ahead of you into Galilee. There you will see him. Now I have told you.","T":"Now go quickly and tell his disciples: He has risen from the dead—and he is going ahead of you to Galilee, where you will see him. This is the message I was sent to deliver."},
  "8": {"L":"And they departed quickly from the tomb with fear and great joy, and ran to bring his disciples word.","M":"So the women hurried away from the tomb, afraid yet filled with joy, and ran to tell his disciples.","T":"The women left the tomb quickly—frightened but overflowing with joy—and ran to tell his disciples."},
  "9": {"L":"And behold, Jesus met them, saying: All hail. And they came and took hold of his feet, and worshipped him.","M":"Suddenly Jesus met them. Greetings, he said. They came to him, clasped his feet and worshipped him.","T":"Suddenly Jesus appeared and met them: Greetings! They came to him, grasped his feet, and worshipped him."},
  "10": {"L":"Then saith Jesus unto them: Fear not; go tell my brethren that they depart into Galilee, and there shall they see me.","M":"Then Jesus said to them: Do not be afraid. Go and tell my brothers to go to Galilee; there they will see me.","T":"Jesus said: Don't be afraid. Go tell my brothers to go to Galilee—they will see me there."},
  "11": {"L":"Now while they were going, behold, some of the guard came into the city, and told unto the chief priests all the things that were come to pass.","M":"While the women were on their way, some of the guards went into the city and reported to the chief priests everything that had happened.","T":"While the women were on their way, some of the guards went into the city and reported everything that had happened to the chief priests."},
  "12": {"L":"And when they were assembled with the elders, and had taken counsel, they gave much money unto the soldiers,","M":"When the chief priests had met with the elders and devised a plan, they gave the soldiers a large sum of money,","T":"The chief priests met with the elders and came up with a plan. They gave the soldiers a large sum of money"},
  "13": {"L":"saying: Say ye, His disciples came by night, and stole him away while we slept.","M":"telling them: You are to say: His disciples came during the night and stole him away while we were asleep.","T":"with these instructions: Tell people his disciples came at night and stole his body while you were asleep."},
  "14": {"L":"And if this come to the governor's ears, we will persuade him, and rid you of care.","M":"If this report gets to the governor, we will satisfy him and keep you out of trouble.","T":"If the governor hears about it, we'll smooth things over with him and keep you out of trouble."},
  "15": {"L":"So they took the money, and did as they were taught; and this saying was spread abroad among the Jews, and continueth until this day.","M":"So the soldiers took the money and did as they were instructed. And this story has been widely circulated among the Jews to this very day.","T":"The soldiers took the money and spread the story as instructed. This account has circulated among the Jewish people to this day."},
  "16": {"L":"But the eleven disciples went into Galilee, unto the mountain where Jesus had appointed them.","M":"Then the eleven disciples went to Galilee, to the mountain where Jesus had told them to go.","T":"The eleven disciples went to Galilee, to the mountain Jesus had specified."},
  "17": {"L":"And when they saw him, they worshipped him; but some doubted.","M":"When they saw him, they worshipped him; but some doubted.","T":"When they saw him, they worshipped—but some hesitated."},
  "18": {"L":"And Jesus came to them and spake unto them, saying: All authority hath been given unto me in heaven and on earth.","M":"Then Jesus came to them and said: All authority in heaven and on earth has been given to me.","T":"Jesus came to them and said: All authority in heaven and on earth has been given to me."},
  "19": {"L":"Go ye therefore, and make disciples of all the nations, baptizing them into the name of the Father and of the Son and of the Holy Spirit;","M":"Therefore go and make disciples of all nations, baptising them in the name of the Father and of the Son and of the Holy Spirit,","T":"Therefore go and make disciples of all nations—baptizing them in the name of the Father and the Son and the Holy Spirit—"},
  "20": {"L":"teaching them to observe all things whatsoever I commanded you; and lo, I am with you always, even unto the end of the age.","M":"and teaching them to obey everything I have commanded you. And surely I am with you always, to the very end of the age.","T":"and teaching them to follow everything I have commanded you. And know this—I am with you every day, until the very end of the age."}
 }
}

def main():
    for tier, key in (('literal','L'), ('mediating','M'), ('thought','T')):
        data = load(tier, 'matthew')
        for ch, verses in MATTHEW.items():
            data[ch] = {v: d[key] for v, d in verses.items()}
        save(tier, 'matthew', data)
    print('Matthew chapters 22-28 written.')

if __name__ == '__main__':
    main()
